SELECT SUM(total_cost) AS total_purchase_cost
FROM purchase_order
WHERE order_date = '2022-01-02';

SELECT COUNT(*)
FROM storage_locations
WHERE location_id = 0;

SELECT alloy_num, AVG(tensile_strength) AS avg_tensile_strength
FROM alloys
GROUP BY alloy_num;

SELECT location_id, COUNT(*) AS number_of_alloys
FROM alloy_storage
GROUP BY location_id;

SELECT alloy_id, COUNT(specification_id) AS specification_count
FROM alloy_specifications
GROUP BY alloy_id;

SELECT COUNT(*) AS alloy_count
FROM alloys
WHERE density > (SELECT AVG(density) FROM alloys);

SELECT alloy_num
FROM alloys
WHERE tensile_strength = (SELECT MAX(tensile_strength) FROM alloys);

SELECT DISTINCT alloy_num
FROM alloys
ORDER BY alloy_num ASC;

SELECT alloy_num
FROM alloys
ORDER BY updated_date DESC;

SELECT alloy_num
FROM alloys
WHERE alloy_id = 1;

SELECT supplier_name
FROM supplier
WHERE supplier_id IN (0, 1);

SELECT alloy_num
FROM alloys
ORDER BY alloy_num ASC;
